import Foundation

/// #98: Curated natural-science question bank for the science game mode.
/// Each level ships ≥50 questions (LK20-aligned: 1.–10. klasse → grunnskole,
/// 11.–13. → VGS, 14.–20. → universitet/avansert). Topics span biology,
/// physics, chemistry, astronomy and geology so a round feels varied rather
/// than single-domain.
///
/// Compact format: `q(prompt, correct, d1, d2, d3)` — one line per question.
/// Distractors are plausible but distinguishable from the correct answer so
/// the four-button grid never renders an ambiguous choice.
enum ScienceQuestionBank {

    typealias Raw = ScienceProblemGenerator.Raw

    static func questions(forLevel level: Int) -> [Raw] {
        switch max(1, min(20, level)) {
        case 1:  return level1
        case 2:  return level2
        case 3:  return level3
        case 4:  return level4
        case 5:  return level5
        case 6:  return level6
        case 7:  return level7
        case 8:  return level8
        case 9:  return level9
        case 10: return level10
        case 11: return level11
        case 12: return level12
        case 13: return level13
        case 14: return level14
        case 15: return level15
        case 16: return level16
        case 17: return level17
        case 18: return level18
        case 19: return level19
        default: return level20
        }
    }

    private static func q(_ p: String, _ c: String, _ d1: String, _ d2: String, _ d3: String) -> Raw {
        Raw(prompt: p, correct: c, distractors: [d1, d2, d3])
    }

